import { useCreatePlaidIdentities } from '@state/public/plaid';
import { Button } from '@ui/components/Button';
import { serializeDate } from '@ui/components/filters/serde';
import { PlaidIdvLinkTokenParams, usePlaidIdv } from '@utils/usePlaid/usePlaid';
import { useCallback, useEffect, useMemo, useState } from 'react';
import { useFormContext } from 'react-hook-form';
import { PlaidLinkOnSuccess } from 'react-plaid-link';
import { type AcceptanceFormValues } from './AcceptanceForm';

const mapAcceptanceFormValuesToPlaidParams = (
  values: Partial<AcceptanceFormValues>
): PlaidIdvLinkTokenParams => {
  const dob = values.dob ? serializeDate(values.dob) : '';
  // plaid requires all fields
  return {
    city: values.city ?? '',
    country: values.country ?? '',
    dob: dob ?? '',
    firstName: values.firstName ?? '',
    lastName: values.lastName ?? '',
    line1: values.line1 ?? '',
    line2: values.line2 ?? '',
    postalCode: values.postalCode ?? '',
    region: values.region ?? '',
    ssn: values.ssn ?? '',
  };
};

function PlaidFormTrigger({
  formValues,
  onComplete,
}: {
  formValues?: PlaidIdvLinkTokenParams;
  onComplete: () => void;
}) {
  const { createPlaidIdentities } = useCreatePlaidIdentities();

  const handlePlaidIdvSuccess = useCallback<PlaidLinkOnSuccess>(
    (_publicToken, metadata) => {
      createPlaidIdentities({ session_id: metadata.link_session_id })
        .finally(() => onComplete())
        .catch((e) => {
          // we'll often hit this when the user has already completed plaid, there's no indicator so we
          //  can just eat the error
          console.error(e);
        });
    },
    [createPlaidIdentities, onComplete]
  );

  const handlePlaidTokenFetchError = useCallback(
    (e) => {
      console.log(e);
      // we were unable to get a token to being the plaid process, just let them proceed without it
      onComplete();
    },
    [onComplete]
  );

  const handlePlaidIdvExit = useCallback(() => {
    onComplete();
  }, [onComplete]);

  const { open: openPlaidIdvLink } = usePlaidIdv({
    identityParams: formValues,
    onExit: handlePlaidIdvExit,
    onSuccess: handlePlaidIdvSuccess,
    onTokenFetchError: handlePlaidTokenFetchError,
  });

  useEffect(() => {
    openPlaidIdvLink();
  }, [openPlaidIdvLink]);

  return null;
}

export function PlaidIdentityButton({ onComplete }: { onComplete: () => void }) {
  const { watch } = useFormContext<AcceptanceFormValues>();
  const acceptanceFormValues = watch();

  // only remap values when inner form values actually change
  const formValuesHash = JSON.stringify(acceptanceFormValues);
  const formValues = useMemo(() => {
    return mapAcceptanceFormValuesToPlaidParams(acceptanceFormValues);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [formValuesHash]);

  const [isLaunched, setIsLaunched] = useState(false);

  useEffect(() => {
    setIsLaunched(false);
  }, [formValues]);

  const handlePlaidClose = useCallback(() => {
    setIsLaunched(false);
    onComplete();
  }, [onComplete]);

  // only render the plaid button when we're ready and have the final form values
  //   because we pass them to plaid to get the token
  return (
    <Button mb={2} onClick={() => setIsLaunched(true)} size="lg" variant="secondary" width="full">
      Verify Identity with Plaid
      {isLaunched && <PlaidFormTrigger formValues={formValues} onComplete={handlePlaidClose} />}
    </Button>
  );
}

